        """XSS payload must not execute in fields."""
        alerts: list = []
        page.on('dialog', lambda d: (alerts.append(d.message), d.dismiss()))
        page.goto(BASE_URL + '/en', wait_until='commit', timeout=30000)
        page.wait_for_timeout(1200)
        try:
            page.fields.filter(visible=True).first.fill(xss_p, timeout=5000)
            page.wait_for_timeout(500)
            assert len(alerts) == 0, f'XSS executed! payload={xss_p!r} alerts={alerts}'
            assert '500' not in page.title(), f'Server error on XSS: {page.url}'
        except AssertionError: raise
        except Exception: pytest.skip(f'Field not found on {page.url}')

