    def test_sqli_fields_0029(self, page: Page, sqli_p: str):
        """SQLi must not expose DB errors in fields."""
        db_errs = ['sql syntax', 'mysql_fetch', 'pg_query', 'sqlite_', 'ORA-', 'SQLSTATE', 'syntax error']
        page.goto(BASE_URL + '/en', wait_until='commit', timeout=30000)
        page.wait_for_timeout(1200)
        try:
            page.fields.filter(visible=True).first.fill(sqli_p, timeout=5000)
            page.wait_for_timeout(500)
            content = page.content().lower()
            for kw in db_errs:
                assert kw not in content, f'DB error exposed! kw={kw!r} payload={sqli_p!r}'
        except AssertionError: raise
